var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はぁ、はぁ、はぁ……！","ENG":"*Huff* *Huff* *Huff...!*","TWN":"哈，哈，哈！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"클리포트 인자를 사용한 참격이 아니었는데도, 이 정도 깊은 상처라니…….","JPN":"クリフォトファクターを用いた斬撃でもなかったのに、これ程の傷とは……","ENG":"That wasn't even a slash using the Qliphoth Factor, and yet, a wound this deep...","TWN":"雖然不是使用神聖因數的斬擊，但竟然造成了如此深的傷口……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"울브즈베인은 신을 죽이는 검…….","JPN":"ウルブズベインは神を殺す剣……","ENG":"The Godslayer, Wolvesbane...","TWN":"狼之災禍是弑神之劍……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 아이러니하게도 마왕 역시 신성한 존재…….","JPN":"そして皮肉なことに魔王もまた神聖な存在……","ENG":"And ironically, a Demon Lord is considered a divine entity...","TWN":"而且諷刺的是，魔王也是神聖的存在……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아마도 사도로서의 힘을 대거 끌어 쓴 이상, 그만큼 그 검에 취약해질 수밖에 없는 거겠죠.","JPN":"使徒としての力を大量に借りた以上、その分あの剣の影響を受けやすくなったのでしょう。","ENG":"By unleashing so much of my power as an Apostle, I must've made myself all the more vulnerable to that blade.","TWN":"或許是因為大量使用了使徒的力量，所以才會對那把劍變得如此脆弱吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇지 않나요, 타기리온……?","JPN":"そうですよね、タギリオン……？","ENG":"Isn't that right, Thagirion...?","TWN":"不是嗎？塔基里翁?"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"후후, 이거 어쩌죠?","JPN":"ふふ、これはこれは。","ENG":"Fu fu, what a shame.","TWN":"呵呵，這可怎麼辦呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"제가 그만 프리마돈나의 무대 뒤편을 봐버리고 말았군요.","JPN":"私としたことが、ついプリマドンナの舞台裏の姿を見てしまいましたね。","ENG":"I ended up peeking behind the prima donna's stage curtain.","TWN":"我不小心看到了歌劇女主角舞台背後的樣子。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 설마 이 정도로 비굴한 모습을 보게 될 줄은 몰랐는데 말이죠.","JPN":"しかしまさか、これ程卑屈な姿を見ることになるとは思いませんでした。","ENG":"Still, I did not expect to see you this pathetic.","TWN":"但沒想到竟然會看到如此卑微的樣子。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"지금 그 모습, 당신의 이름과는 걸맞지 않네요, 스완 클레어.","JPN":"今のあなたは、到底その名を冠するに値する人物には見えませんね、スワン・クレア。","ENG":"This look doesn't suit you at all, Swan Claire.","TWN":"現在的樣子，與你的名字不相稱呢，史旺·克萊爾。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 그야 당연하겠죠.","JPN":"ふふ、当然のことです。","ENG":"Haha. Well, of course not.","TWN":"呵呵，那不是廢話吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 백조가 되길 바랐을 뿐이지, 백조였던 적은 단 한 번도 없습니다.","JPN":"私は白鳥になることに憧れただけで、一度も白鳥であったことはありませんでした。","ENG":"I only ever wanted to be a swan, but never was I to become one.","TWN":"我只是希望成為一隻天鵝，但從來沒有真正成為過天鵝。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"단 한 순간도 살아남기 위한, 발버둥을 멈춘 적이 없으니까요.","JPN":"一瞬たりとも生き残るための足掻きを止めませんでしたから。","ENG":"Not once did I stop struggling to survive, not even for a moment.","TWN":"因為我哪怕一瞬間都從未停止過掙扎求生的努力。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"보세요, 지금 이 순간도 살기 위해, 몸을 낮춰 당신의 하수인을 자처하고 있잖아요?","JPN":"ほら、今この瞬間も生き残るために、身を屈めてあなたの手先を買って出ているでしょう？","ENG":"Look at me now. Even now, I'm groveling to you, calling myself your underling, just to stay alive.","TWN":"看看吧，即使在這一刻，為了活下去，我也願意屈身成為你的僕人，不是嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 이상하네요.","JPN":"しかし、妙ですね。","ENG":"And yet, it's strange.","TWN":"不過有點奇怪啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그렇게 목숨이 아까운 당신이 어째서 계획에도 없는 일을 벌인 거죠?","JPN":"そんなに命が惜しいあなたが、どうして計画にもないことをしたんですか？","ENG":"Why would someone who clings so desperately to life go so far off script?","TWN":"既然你如此珍惜生命，為什麼？做計畫之外的事情呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그것도 당신 스스로의 목숨까지 걸고서 말이죠.","JPN":"それもあなた自身の命まで賭けて。","ENG":"Going as far as to risk her own life?","TWN":"而且還是賭上自己的性命。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 당신이 순순히 계약을 지킨다는 확신이 있다면 이런 짓을 벌일 필요가 없었겠죠.","JPN":"さて、どうでしょう。あなたが素直に契約を守るであろう確信があれば、このようなことをする必要はなかったでしょうね。","ENG":"Well, if I had any faith that you'd honor the deal, I wouldn't have needed to.","TWN":"嗯，如果我確信你會乖乖履行契約，那就沒必要做這種事了吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 계약 조건은 어디까지나, 당신을 현실로 강림하게 만드는 것.","JPN":"私の契約の条件は、あくまであなたを現実に降臨させること。","ENG":"My end of the contract was to bring you into reality.","TWN":"我的契約條件只是讓你降臨到現實中。"},"stage":{"bg":"MS_1201","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이를 위해, 여섯 곳의 대균열에 거울 조각을 심었고, 방주의 봉인을 붕괴시켰습니다.","JPN":"そのために、6つの大亀裂に鏡の破片を植え込み、箱舟の封印を崩壊させました。","ENG":"To do that, I planted mirror shards in all six Grand Dimension Crevices and shattered the Ark's seal.","TWN":"為此，我們在六個大裂縫中植入了鏡子碎片，並破壞了方舟的封印。"},"stage":{"bg":"MS_1201","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"봉인을 무너트렸으니, 머지않아 당신은 현실에 강림할 힘을 얻게 되겠죠.","JPN":"封印を壊したので、間もなくあなたは現実に降臨する力を得られることでしょう。","ENG":"Now that the seal is broken, you'll soon gain the power to manifest in reality.","TWN":"既然已經打破封印，不久之後你就會獲得降臨現實的力量吧。"},"stage":{"bg":"MS_1201","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 저는 당신과의 계약을 충실히 이행했습니다.","JPN":"私はあなたとの契約を忠実に履行しました。","ENG":"In other words, I've fulfilled my part of the bargain.","TWN":"所以我忠實地履行了與你的契約。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 당신이 계약대로 저에게 소원을 넘겨준다는 보장은 어디에도 없죠.","JPN":"しかし､あなたが契約通り、願いを私に譲るという保証はどこにもない。","ENG":"But there's no guarantee you'll grant my wish in return.","TWN":"但是沒有任何保證能確保你會按契約把願望交給我。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서 제 나름대로 고향 세계 런던을 되돌리려 한 겁니다.","JPN":"だから、私なりに故郷の世界のロンドンを元に戻そうとしたまでです。","ENG":"So I made my own attempt to restore London, my home world.","TWN":"所以我才想盡辦法恢復故鄉世界倫敦的樣子。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이제 이해가 되시나요, 암군이여?","JPN":"これでおわかりいただけましたか？　暗君。","ENG":"Do you understand now, Ignorant Monarch?","TWN":"現在明白了嗎？暗君？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};